Explain how this script works?

<#
Partner Center + GDAP (Graph) Customer Report
Auth model:
- Partner Center: MSAL.PS using the existing working public clientId (1950a258-...)
- Microsoft Graph (GDAP): Microsoft Graph PowerShell SDK (Connect-MgGraph) using Microsoft’s built-in enterprise app
  (avoids creating your own app registration). :contentReference[oaicite:2]{index=2}

CSV columns:
CustomerName, TenantID, GDAP Enabled y/n, GDAP start date, GDAP end date,
Microsoft Entra Roles, AdminAgents y/n, HelpdeskAgents y/n, AdminAgents Roles, HelpdeskAgents Roles
#>

# ----------------------------
# 0) Settings
# ----------------------------
$PartnerCenterClientId = "1950a258-227b-4e31-a9cf-717495945fc2"  # keep
$TenantIdForAuth = "common"  # or your partner tenant ID (recommended if known)

# Your partner-tenant group display names used for GDAP role assignment
$AdminAgentsGroupName    = "AdminAgents"
$HelpdeskAgentsGroupName = "HelpdeskAgents"

# Output
$desktop = [Environment]::GetFolderPath("Desktop")
$outPath = Join-Path $desktop "Customers_GDAP_Report.csv"

# Throttle
$PerCustomerDelayMs = 50

# ----------------------------
# 1) Ensure modules
# ----------------------------
if (-not (Get-Module -ListAvailable -Name MSAL.PS)) {
    Write-Host "MSAL.PS module not found. Installing..."
    Install-Module MSAL.PS -Scope CurrentUser -Force -AllowClobber
}

if (-not (Get-Module -ListAvailable -Name Microsoft.Graph)) {
    Write-Host "Microsoft.Graph module not found. Installing..."
    Install-Module Microsoft.Graph -Scope CurrentUser -Force -AllowClobber
}

# ----------------------------
# 2) Helpers
# ----------------------------
function Escape-ODataString {
    param([string]$s)
    return ($s -replace "'", "''")
}

function Invoke-RestGetWithRetry {
    param(
        [Parameter(Mandatory)] [string] $Uri,
        [Parameter(Mandatory)] [hashtable] $Headers,
        [int] $MaxRetries = 6
    )

    $attempt = 0
    while ($true) {
        try {
            return Invoke-RestMethod -Method GET -Uri $Uri -Headers $Headers
        }
        catch {
            $attempt++
            $statusCode = $null
            $retryAfter = $null

            try {
                $statusCode = $_.Exception.Response.StatusCode.value__
                $retryAfter = $_.Exception.Response.Headers["Retry-After"]
            } catch { }

            if ($attempt -gt $MaxRetries) { throw }

            $sleepSec = 0
            if ($retryAfter) {
                [int]$sleepSec = $retryAfter[0]
                if ($sleepSec -lt 1) { $sleepSec = 1 }
            } else {
                $sleepSec = [math]::Min(60, [math]::Pow(2, $attempt))
            }

            Write-Warning "GET failed ($statusCode). Retry $attempt/$MaxRetries in $sleepSec sec. Uri: $Uri"
            Start-Sleep -Seconds $sleepSec
        }
    }
}

function Invoke-PartnerCenterGetAll {
    param(
        [Parameter(Mandatory)] [string] $Uri,
        [Parameter(Mandatory)] [hashtable] $Headers
    )

    $items = @()
    $next  = $Uri

    while ($next) {
        $resp = Invoke-RestGetWithRetry -Uri $next -Headers $Headers
        if ($resp.items) { $items += $resp.items }

        $nextLink = $null
        if ($resp.links -and $resp.links.next -and $resp.links.next.uri) {
            $nextLink = $resp.links.next.uri
        }
        $next = $nextLink
    }

    return $items
}

function Invoke-MgGetAll {
    param(
        [Parameter(Mandatory)] [string] $Uri
    )

    # Uses the current Connect-MgGraph context/token
    $items = @()
    $next = $Uri

    while ($next) {
        $resp = Invoke-MgGraphRequest -Method GET -Uri $next

        if ($resp.value) { $items += $resp.value }

        # nextLink is a property name with @ in it; access via PSObject
        $nextLinkProp = $resp.PSObject.Properties.Name | Where-Object { $_ -eq "@odata.nextLink" }
        if ($nextLinkProp) {
            $next = $resp."@odata.nextLink"
        } else {
            $next = $null
        }
    }

    return $items
}

# ----------------------------
# 3) Partner Center auth (MSAL.PS)
# ----------------------------
Write-Host "AUTHENTICATE for Partner Center as CSP user (e.g., bspilker@presidiocsp.onmicrosoft.com)"
try {
    $pcToken = Get-MsalToken -ClientId $PartnerCenterClientId -TenantId $TenantIdForAuth `
        -Scopes "https://api.partnercenter.microsoft.com/.default" `
        -Interactive -UseEmbeddedWebView
}
catch {
    Write-Error "Partner Center authentication failed: $_"
    exit 1
}

$pcHeaders = @{ Authorization = "Bearer $($pcToken.AccessToken)" }

# ----------------------------
# 4) Microsoft Graph auth (NO app registration) via Graph PowerShell SDK
# ----------------------------
# Scopes needed for GDAP + resolving roles/groups
# Note: Tenant may require admin consent for these.
$graphScopes = @(
    "DelegatedAdminRelationship.Read.All",
    "RoleManagement.Read.Directory",
    "Group.Read.All"
)

Write-Host "AUTHENTICATE to Microsoft Graph (Connect-MgGraph) as your user..."
try {
    Connect-MgGraph -Scopes $graphScopes -NoWelcome | Out-Null
}
catch {
    Write-Error "Connect-MgGraph failed: $($_.Exception.Message)"
    exit 1
}

# ----------------------------
# 5) Cache Entra role definitions (id -> displayName)
# ----------------------------
Write-Host "Caching Entra role definitions..."
$roleMap = @{}
$roleDefs = Invoke-MgGetAll -Uri "https://graph.microsoft.com/v1.0/roleManagement/directory/roleDefinitions?`$select=id,displayName"
foreach ($rd in $roleDefs) {
    if ($rd.id -and $rd.displayName) { $roleMap[$rd.id] = $rd.displayName }
}

# ----------------------------
# 6) Resolve AdminAgents / HelpdeskAgents group IDs in partner tenant
# ----------------------------
Write-Host "Resolving group IDs for '$AdminAgentsGroupName' and '$HelpdeskAgentsGroupName'..."
$adminAgentsGroupId = $null
$helpdeskAgentsGroupId = $null

$adminEsc = Escape-ODataString $AdminAgentsGroupName
$helpEsc  = Escape-ODataString $HelpdeskAgentsGroupName

$adminGroups = Invoke-MgGetAll -Uri "https://graph.microsoft.com/v1.0/groups?`$filter=displayName eq '$adminEsc'&`$select=id,displayName"
$helpGroups  = Invoke-MgGetAll -Uri "https://graph.microsoft.com/v1.0/groups?`$filter=displayName eq '$helpEsc'&`$select=id,displayName"

if ($adminGroups.Count -gt 0) { $adminAgentsGroupId = $adminGroups[0].id }
if ($helpGroups.Count -gt 0)  { $helpdeskAgentsGroupId = $helpGroups[0].id }

if (-not $adminAgentsGroupId)    { Write-Warning "Group '$AdminAgentsGroupName' not found. AdminAgents columns will be N/blank." }
if (-not $helpdeskAgentsGroupId) { Write-Warning "Group '$HelpdeskAgentsGroupName' not found. HelpdeskAgents columns will be N/blank." }

# ----------------------------
# 7) Get customers from Partner Center
# ----------------------------
Write-Host "Fetching customers from Partner Center..."
$customers = Invoke-PartnerCenterGetAll -Uri "https://api.partnercenter.microsoft.com/v1/customers" -Headers $pcHeaders
$totalCustomers = $customers.Count
Write-Host "Total customers retrieved: $totalCustomers"

# ----------------------------
# 8) Build report
# ----------------------------
$rows = New-Object System.Collections.Generic.List[Object]

for ($i = 0; $i -lt $totalCustomers; $i++) {
    $customer = $customers[$i]
    $customerName = $customer.companyProfile.companyName
    $customerTenantId = $customer.companyProfile.tenantId

    Write-Progress -PercentComplete (($i / [math]::Max(1,$totalCustomers)) * 100) `
        -Activity "Checking GDAP for $customerName" `
        -Status "Customer $($i + 1) of $totalCustomers"

    # Defaults
    $gdapEnabled = "N"
    $gdapStart = $null
    $gdapEnd   = $null

    $allRoleNames = @()
    $adminAgentsYN = "N"
    $helpdeskAgentsYN = "N"
    $adminAgentsRoles = @()
    $helpdeskAgentsRoles = @()

    try {
        if ([string]::IsNullOrWhiteSpace($customerTenantId)) {
            throw "Customer tenantId missing in Partner Center record."
        }

        # Find ACTIVE GDAP relationships for this customer tenant
        $tidEsc = Escape-ODataString $customerTenantId
        $rels = Invoke-MgGetAll -Uri "https://graph.microsoft.com/v1.0/tenantRelationships/delegatedAdminRelationships?`$filter=customer/tenantId eq '$tidEsc' and status eq 'active'"

        if ($rels.Count -gt 0) {
            # Choose relationship with latest endDateTime if multiple
            $rel = $rels | Sort-Object endDateTime -Descending | Select-Object -First 1

            $gdapEnabled = "Y"
            $gdapStart = $rel.activatedDateTime
            $gdapEnd   = $rel.endDateTime

            # Access assignments (which group got which roles)
            $assignments = Invoke-MgGetAll -Uri "https://graph.microsoft.com/v1.0/tenantRelationships/delegatedAdminRelationships/$($rel.id)/accessAssignments"

            foreach ($a in $assignments) {
                # Role IDs
                $roleIds = @()
                if ($a.accessDetails -and $a.accessDetails.roleDefinitionIds) {
                    $roleIds = @($a.accessDetails.roleDefinitionIds)
                }

                # Resolve to names
                $roleNames = foreach ($rid in $roleIds) {
                    if ($roleMap.ContainsKey($rid)) { $roleMap[$rid] } else { $rid }
                }

                $allRoleNames += $roleNames

                # Group/container
                $containerId = $null
                if ($a.accessContainer -and $a.accessContainer.id) {
                    $containerId = $a.accessContainer.id
                }

                if ($adminAgentsGroupId -and $containerId -eq $adminAgentsGroupId) {
                    $adminAgentsYN = "Y"
                    $adminAgentsRoles += $roleNames
                }

                if ($helpdeskAgentsGroupId -and $containerId -eq $helpdeskAgentsGroupId) {
                    $helpdeskAgentsYN = "Y"
                    $helpdeskAgentsRoles += $roleNames
                }
            }
        }
    }
    catch {
        Write-Warning "GDAP lookup failed for '$customerName' (TenantId: $customerTenantId). Error: $($_.Exception.Message)"
    }

    # Clean lists
    $allRoleNames        = $allRoleNames        | Where-Object { $_ } | Sort-Object -Unique
    $adminAgentsRoles    = $adminAgentsRoles    | Where-Object { $_ } | Sort-Object -Unique
    $helpdeskAgentsRoles = $helpdeskAgentsRoles | Where-Object { $_ } | Sort-Object -Unique

    $rows.Add([PSCustomObject]@{
        CustomerName             = $customerName
        TenantID                 = $customerTenantId
        "GDAP Enabled y/n"        = $gdapEnabled
        "GDAP start date"         = $gdapStart
        "GDAP end date"           = $gdapEnd
        "Microsoft Entra Roles"   = ($allRoleNames -join "; ")
        "AdminAgents y/n"         = $adminAgentsYN
        "HelpdeskAgents y/n"      = $helpdeskAgentsYN
        "AdminAgents Roles"       = ($adminAgentsRoles -join "; ")
        "HelpdeskAgents Roles"    = ($helpdeskAgentsRoles -join "; ")
    })

    if ($PerCustomerDelayMs -gt 0) { Start-Sleep -Milliseconds $PerCustomerDelayMs }
}

# ----------------------------
# 9) Export
# ----------------------------
$rows | Sort-Object CustomerName | Export-Csv -Path $outPath -NoTypeInformation

Write-Host "`nProcessing complete."
Write-Host "GDAP report exported to:`n   $outPath"

